import React, { useState, useEffect } from 'react';
import { Link, NavLink, useLocation } from 'react-router-dom';
import './Navbar.css';

function Navbar() {
  const [menuOpen, setMenuOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Close mobile menu on route change
  useEffect(() => {
    setMenuOpen(false);
  }, [location]);

  return (
    <header className={`navbar ${scrolled ? 'navbar--scrolled' : ''}`}>
      <div className="navbar__container">
        {/* Logo */}
        <Link to="/" className="navbar__logo">
          <span className="navbar__logo-icon">✦</span>
          Model<span className="navbar__logo-accent">Vogue</span>
        </Link>

        {/* Desktop Nav */}
        <nav className="navbar__links">
          <NavLink to="/" end className={({ isActive }) => isActive ? 'navbar__link active' : 'navbar__link'}>Home</NavLink>
          <NavLink to="/events" className={({ isActive }) => isActive ? 'navbar__link active' : 'navbar__link'}>Events</NavLink>
          <NavLink to="/models" className={({ isActive }) => isActive ? 'navbar__link active' : 'navbar__link'}>Models</NavLink>
          <NavLink to="/contact" className={({ isActive }) => isActive ? 'navbar__link active' : 'navbar__link'}>Contact</NavLink>
        </nav>

        {/* CTA */}
        <Link to="/events" className="navbar__cta btn-primary">Book a Seat</Link>

        {/* Hamburger */}
        <button
          className={`navbar__hamburger ${menuOpen ? 'open' : ''}`}
          onClick={() => setMenuOpen(!menuOpen)}
          aria-label="Toggle menu"
        >
          <span /><span /><span />
        </button>
      </div>

      {/* Mobile Menu */}
      {menuOpen && (
        <div className="navbar__mobile-menu">
          <NavLink to="/" end className="navbar__mobile-link">Home</NavLink>
          <NavLink to="/events" className="navbar__mobile-link">Events</NavLink>
          <NavLink to="/models" className="navbar__mobile-link">Models</NavLink>
          <NavLink to="/contact" className="navbar__mobile-link">Contact</NavLink>
          <Link to="/events" className="btn-primary" style={{ marginTop: '12px', textAlign: 'center' }}>Book a Seat</Link>
        </div>
      )}
    </header>
  );
}

export default Navbar;
